from collections import deque

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    # Extract panels (5x5 inner)
    p0 = [grid[r][1:6] for r in range(1, H-1)]
    p1 = [grid[r][7:12] for r in range(1, H-1)]  # PA
    p2 = [grid[r][13:18] for r in range(1, H-1)]  # PB

    rows, cols = len(p0), len(p0[0])

    # Inner background
    from collections import Counter
    flat = [p0[r][c] for r in range(rows) for c in range(cols)]
    ibg = Counter(flat).most_common(1)[0][0]

    # P0 non-ibg cells
    p0_cells = set()
    for r in range(rows):
        for c in range(cols):
            if p0[r][c] != ibg:
                p0_cells.add((r, c))

    # Find connected components of P0 cells (8-connected)
    visited = set()
    components = []
    for cell in p0_cells:
        if cell in visited:
            continue
        comp = set()
        queue = deque([cell])
        while queue:
            cr, cc = queue.popleft()
            if (cr, cc) in visited:
                continue
            visited.add((cr, cc))
            comp.add((cr, cc))
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0:
                        continue
                    nr, nc = cr + dr, cc + dc
                    if (nr, nc) in p0_cells and (nr, nc) not in visited:
                        queue.append((nr, nc))
        components.append(comp)

    # Main component = largest, extra cell = smallest component (should be single cell)
    components.sort(key=len, reverse=True)
    main_boundary = components[0]
    extra_cell = list(components[1])[0] if len(components) > 1 else None

    # Flood fill ibg cells (4-connected) to find regions
    region_map = {}  # (r,c) -> region_id
    regions = []
    for sr in range(rows):
        for sc in range(cols):
            if (sr, sc) in p0_cells or (sr, sc) in region_map:
                continue
            region = set()
            queue = deque([(sr, sc)])
            while queue:
                cr, cc = queue.popleft()
                if (cr, cc) in region_map or (cr, cc) in p0_cells:
                    continue
                if cr < 0 or cr >= rows or cc < 0 or cc >= cols:
                    continue
                region_map[(cr, cc)] = len(regions)
                region.add((cr, cc))
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = cr + dr, cc + dc
                    if 0 <= nr < rows and 0 <= nc < cols and (nr, nc) not in region_map and (nr, nc) not in p0_cells:
                        queue.append((nr, nc))
            regions.append(region)

    # Find which region the extra cell is adjacent to (4-connected)
    pa_region_id = None
    if extra_cell:
        er, ec = extra_cell
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = er + dr, ec + dc
            if (nr, nc) in region_map:
                pa_region_id = region_map[(nr, nc)]
                break

    # Build output panel
    out_panel = [[ibg]*cols for _ in range(rows)]

    for r in range(rows):
        for c in range(cols):
            if (r, c) in p0_cells:
                if (r, c) == extra_cell:
                    # Extra cell: PA only
                    out_panel[r][c] = p1[r][c]
                else:
                    # Main boundary: PA priority, then PB
                    if p1[r][c] != ibg:
                        out_panel[r][c] = p1[r][c]
                    elif p2[r][c] != ibg:
                        out_panel[r][c] = p2[r][c]
                    else:
                        out_panel[r][c] = ibg
            elif (r, c) in region_map:
                rid = region_map[(r, c)]
                if rid == pa_region_id:
                    out_panel[r][c] = p1[r][c]  # PA
                else:
                    out_panel[r][c] = p2[r][c]  # PB

    # Place output panel back into grid
    output = [list(row) for row in grid]
    for r in range(rows):
        for c in range(cols):
            output[r+1][19+c] = out_panel[r][c]

    return output

# Test on all training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        for r in range(len(result)):
            for c in range(len(result[0])):
                if result[r][c] != expected[r][c]:
                    print(f"  Diff at ({r},{c}): got {result[r][c]}, expected {expected[r][c]}")

